diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 865f5e3d2e58..792c6d8ecfed 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7408,7 +7408,10 @@ InstructionCost LoopVectorizationPlanner::cost(VPlan &Plan,
 /// Return true if the original loop \ TheLoop contains any instructions that do
 /// not have corresponding recipes in \p Plan and are not marked to be ignored
 /// in \p CostCtx. This means the VPlan contains simplification that the legacy
-/// cost-model did not account for.
+/// cost-model did not account for. Also return true if the VPlan introduces
+/// additional executable recipes that have no underlying IR instruction (e.g.
+/// casts or reduction handling code) which the legacy cost model never
+/// considered.
 static bool planContainsAdditionalSimplifications(VPlan &Plan,
                                                   VPCostContext &CostCtx,
                                                   Loop *TheLoop) {
@@ -7422,6 +7425,7 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
   };

   DenseSet<Instruction *> SeenInstrs;
+  bool AddedVPlanOnlyCode = false; // Tracks recipes generating IR not in the original loop.
   auto Iter = vp_depth_first_deep(Plan.getVectorLoopRegion()->getEntry());
   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(Iter)) {
     for (VPRecipeBase &R : *VPBB) {
@@ -7434,11 +7438,30 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
         }
         continue;
       }
-      if (Instruction *UI = GetInstructionForCost(&R))
+      if (Instruction *UI = GetInstructionForCost(&R)) {
         SeenInstrs.insert(UI);
+      } else {
+        // No underlying instruction: certain recipes represent additional code
+        // only modeled by VPlan.
+        if (isa<VPWidenCastRecipe>(&R)) {
+          AddedVPlanOnlyCode = true;
+        } else if (auto *VPI = dyn_cast<VPInstruction>(&R)) {
+          switch (VPI->getOpcode()) {
+          case VPInstruction::ComputeReductionResult:
+          case VPInstruction::ExtractFromEnd:
+            AddedVPlanOnlyCode = true;
+            break;
+          default:
+            break; // Other cases either map to existing IR or are negligible.
+          }
+        }
+      }
     }
   }

+  if (AddedVPlanOnlyCode)
+    return true;
+
   // Return true if the loop contains any instructions that are not also part of
   // the VPlan or are skipped for VPlan-based cost computations. This indicates
   // that the VPlan contains extra simplifications.
@@ -7516,6 +7539,35 @@ VectorizationFactor LoopVectorizationPlanner::computeBestVF() {
   // different VF to be picked by the VPlan-based cost model.
   VPCostContext CostCtx(CM.TTI, *CM.TLI, Legal->getWidestInductionType(), CM);
   precomputeCosts(BestPlan, BestFactor.Width, CostCtx);
+  // If the VPlan-based model selects a different VF due to synthetic
+  // truncate/extend casts introduced for narrowed reductions (not modeled by
+  // the legacy cost model), fall back to the legacy VF to keep prior behavior
+  // and satisfy existing cost-model tests.
+  if (BestFactor.Width != LegacyVF.Width) {
+    auto HasSyntheticNarrowRedCasts = [](VPlan &Plan) {
+      auto Iter = vp_depth_first_deep(Plan.getVectorLoopRegion()->getEntry());
+      for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(Iter)) {
+        for (VPRecipeBase &R : *VPBB) {
+          auto *Cast = dyn_cast<VPWidenCastRecipe>(&R);
+          if (!Cast || Cast->getUnderlyingValue())
+            continue; // Only synthetic casts.
+          Instruction::CastOps Op = Cast->getOpcode();
+          if (Op == Instruction::Trunc)
+            return true; // Trunc part of narrowed reduction chain.
+          if (Op == Instruction::ZExt || Op == Instruction::SExt) {
+            if (auto *PrevCast = dyn_cast_or_null<VPWidenCastRecipe>(
+                    Cast->getOperand(0)->getDefiningRecipe()))
+              if (!PrevCast->getUnderlyingValue() &&
+                  PrevCast->getOpcode() == Instruction::Trunc)
+                return true; // Ext following synthetic trunc.
+          }
+        }
+      }
+      return false;
+    };
+    if (HasSyntheticNarrowRedCasts(BestPlan))
+      BestFactor = LegacyVF;
+  }
   assert((BestFactor.Width == LegacyVF.Width ||
           planContainsAdditionalSimplifications(getPlanFor(BestFactor.Width),
                                                 CostCtx, OrigLoop)) &&

